def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds concise, natural‑language clauses that are then combined into a
    single complex sentence.
    """
    if not triples:
        return ""

    # Normalise object strings (remove surrounding quotes and whitespace)
    def clean_obj(o: str) -> str:
        return o.strip().strip('"')

    # Helper to format ISO dates nicely
    def fmt_date(d: str) -> str:
        try:
            from datetime import datetime
            dt = datetime.strptime(d, "%Y-%m-%d")
            # Use platform‑independent day formatting
            return dt.strftime("%B {day}, %Y").format(day=dt.day)
        except Exception:
            return d

    # Build a mapping: subject -> list of (predicate, object)
    subj_map: dict[str, list[tuple[str, str]]] = {}
    for t in triples:
        subj_map.setdefault(t.subject, []).append((t.predicate, t.object))

    # Produce a clause for each subject
    clauses: list[str] = []
    for subj, preds in subj_map.items():
        parts: list[str] = [subj]  # start with the subject name
        for pred, obj_raw in preds:
            obj = clean_obj(obj_raw)
            p = pred.lower().replace(" ", "")

            if p == "birthdate":
                parts.append(f"was born on {fmt_date(obj)}")
            elif p == "birthplace":
                parts.append(f"was born in {obj}")
            elif p == "deathdate":
                parts.append(f"died on {fmt_date(obj)}")
            elif p == "deathplace":
                parts.append(f"died in {obj}")
            elif p == "nationality":
                if obj == "United States":
                    parts.append("is an American")
                elif obj == "United Kingdom":
                    parts.append("is British")
                else:
                    parts.append(f"is {obj}")
            elif p == "occupation":
                parts.append(f"was a {obj}")
            elif p == "status":
                low = obj.lower()
                if low == "retired":
                    parts.append("is retired")
                elif low == "active":
                    parts.append("is active")
                else:
                    parts.append(f"has status {obj}")
            elif p == "selectedbynasa":
                parts.append(f"was selected by NASA in {obj}")
            elif p == "mission":
                # astronaut -> mission
                parts.append(f"served on {obj}")
            elif p == "timeinspace":
                try:
                    mins = float(obj)
                    hrs = int(mins // 60)
                    rem = int(mins % 60)
                    if hrs:
                        time_str = f"{hrs} hour{'s' if hrs > 1 else ''}"
                        if rem:
                            time_str += f" and {rem} minute{'s' if rem != 1 else ''}"
                    else:
                        time_str = f"{rem} minute{'s' if rem != 1 else ''}"
                    parts.append(f"spent {time_str} in space")
                except Exception:
                    parts.append(f"spent {obj} minutes in space")
            elif p == "title":
                parts.append(f"held the title of {obj}")
            elif p == "award":
                parts.append(f"received the {obj}")
            elif p == "awards":
                parts.append(f"received {obj} awards")
            elif p == "ribbonaward":
                parts.append(f"was awarded the {obj}")
            elif p == "operator":
                # mission -> operator
                article = "" if subj.lower().startswith(("the ", "a ")) else "The "
                parts[0] = f"{article}{subj}"
                parts.append(f"was operated by {obj}")
            elif p == "commander":
                parts.append(f"was commanded by {obj}")
            elif p == "backuppilot":
                parts.append(f"had {obj} as backup pilot")
            elif p == "crewmembers":
                parts.append(f"had {obj} as a crew member")
            elif p == "alternativename":
                parts.append(f"is also known as {obj}")
            elif p == "servedaschiefoftheastronautofficein":
                parts.append(f"served as Chief of the Astronaut Office in {obj}")
            elif p == "representative":
                parts.append(f"was represented by {obj}")
            elif p == "bird":
                parts.append(f"is the state bird of {subj}")
            elif p == "partstype":
                parts.append(f"has parts type {obj}")
            else:
                parts.append(f"{pred} {obj}")

        # Join parts for this subject; first part already contains the subject
        clause = " ".join(parts)
        clauses.append(clause)

    # Combine all subject clauses into a single sentence
    if not clauses:
        return ""
    if len(clauses) == 1:
        sentence = clauses[0]
    else:
        sentence = "; ".join(clauses[:-1]) + "; and " + clauses[-1]
    return sentence + "."

# EVOLVE-BLOCK-END

